"use client";

import { motion, useScroll, useTransform } from "framer-motion";
import { useRef } from "react";
import Image from "next/image";

// Placeholder Logos
const LOGOS = [
    "Piper", "Leybold", "coinbase", "burda style", "Unity", "Atlas Copco", "ONE DROP", "BLOCK PARTY", "BANOVO", "toolchain", "supstat ANALYTICS", "LTSE"
];

type SquareOverlay = {
    top?: string;
    bottom?: string;
    left?: string;
    right?: string;
    size: string;
    type?: 'diamond' | 'triangle' | 'square';
};

type ValueCard = {
    title: string;
    desc: string;
    img: string;
    squares: SquareOverlay[];
};

const VALUES: ValueCard[] = [
    {
        title: "Be curious",
        desc: "Search for how things are done, and how they can be done better. Challenge status quo.",
        img: "https://images.unsplash.com/photo-1522071820081-009f0129c71c?w=800&q=80",
        squares: [
            { top: "-4%", left: "-4%", size: "12" },
            { top: "-4%", right: "-4%", size: "16" },
            { bottom: "-4%", left: "20%", size: "10" }
        ]
    },
    {
        title: "Grow",
        desc: "Grow knowledge and skills and lift others along the way. Personal and business growth go hand in hand.",
        img: "https://images.unsplash.com/photo-1552664730-d307ca884978?w=800&q=80",
        squares: [
            { top: "10%", right: "-8%", size: "24", type: "diamond" }
        ] // Uses a large diamond shape overlay
    },
    {
        title: "Be accountable",
        desc: "Own the s**t when it's good, and when it's not. Stay behind your decisions, gut and knowledge.",
        img: "https://images.unsplash.com/photo-1600880292203-757bb62b4baf?w=800&q=80",
        squares: [
            { top: "30%", left: "-10%", size: "16" },
            { bottom: "10%", left: "10%", size: "12" }
        ]
    },
    {
        title: "Act long run",
        desc: "Work in sprints, but think like a marathoner. Long term results matter.",
        img: "https://images.unsplash.com/photo-1552581234-26160f608093?w=800&q=80",
        squares: [
            { bottom: "-5%", right: "-5%", size: "20", type: "triangle" }
        ]
    }
];

export default function AboutPage() {
    const containerRef = useRef<HTMLDivElement>(null);
    const { scrollYProgress } = useScroll({
        target: containerRef,
        offset: ["start start", "end end"]
    });

    // Animation Transforms for the geometric grid
    const scale = useTransform(scrollYProgress, [0, 0.5, 1], [1, 1.2, 1]);
    const rotate = useTransform(scrollYProgress, [0, 1], [0, 90]);
    const borderRadius = useTransform(scrollYProgress, [0, 0.5, 1], ["0%", "50%", "0%"]);

    return (
        <main className="bg-white min-h-screen text-black font-sans pt-24">
            {/* 1. Our Story Section */}
            <section className="py-24 container mx-auto px-6 md:px-12">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-16 items-start">
                    <motion.h1
                        initial={{ opacity: 0, y: 20 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                        className="text-6xl md:text-8xl font-serif tracking-tight"
                    >
                        Our Story
                    </motion.h1>
                    <motion.div
                        initial={{ opacity: 0, y: 20 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                        transition={{ delay: 0.2 }}
                        className="text-lg md:text-xl text-gray-700 leading-relaxed font-sans max-w-prose"
                    >
                        Itekako is an IT software development company founded more than 15 years ago with the idea to create a friendly and enthusiastic work environment where work-life balance and innovative projects make people happy to come on Mondays. That enthusiasm, a sense of accountability, and a pursuit for excellence in delivery enabled us to grow to 150+ people, 200+ successful projects in 11+ industries, so far.
                    </motion.div>
                </div>

                {/* Client Logos Row */}
                <div className="mt-32 overflow-hidden py-10 border-t border-gray-100 relative">
                    <div className="flex animate-marquee whitespace-nowrap gap-16 items-center">
                        {[...LOGOS, ...LOGOS].map((logo, i) => (
                            <div key={i} className="text-2xl font-bold text-gray-400 uppercase tracking-widest shrink-0">
                                {logo}
                            </div>
                        ))}
                    </div>
                </div>
            </section>

            {/* 2. Sticky Scroll Sections (How we do things & Our Mission) */}
            <section ref={containerRef} className="relative h-[200vh]">
                <div className="sticky top-0 h-screen w-full flex">
                    {/* Left Side: Scrolling Content Masked */}
                    <div className="w-1/2 h-full relative overflow-hidden bg-white">
                        <motion.div
                            style={{ y: useTransform(scrollYProgress, [0, 1], ["0%", "-50%"]) }}
                            className="absolute top-0 left-0 w-full"
                        >
                            {/* Box 1: How we do things */}
                            <div className="h-screen flex flex-col justify-center px-12 lg:px-24">
                                <h2 className="text-6xl md:text-7xl font-serif mb-12">How we do<br />things</h2>
                                <div className="space-y-6 text-lg text-gray-700 max-w-lg">
                                    <p>At Itekako, we're all about mixing tech smarts with a dash of 'Itekako magic' to deliver the best possible digital products for our clients.</p>
                                    <p>We run in sprints (agile, usually), but essentially we are marathoners - the people we work with and the clients we work for have been with us for a long time.</p>
                                    <p>We're all about IT (that's information tech) and 'kako' (that's Serbian for 'how') —which means we're crazy curious about everything we do.</p>
                                </div>
                            </div>

                            {/* Box 2: Our Mission */}
                            <div className="h-screen flex flex-col justify-center px-12 lg:px-24">
                                <h2 className="text-6xl md:text-7xl font-serif mb-12">Our Mission</h2>
                                <div className="space-y-6 text-lg text-gray-700 max-w-lg">
                                    <p>At Itekako, our mission is to ignite businesses worldwide with cutting-edge software solutions. We create, build, and scale all things digital, serving startups, scale-ups, and big players.</p>
                                    <p>Through teamwork, our tech wizardry, and a relentless pursuit of awesomeness, we help our clients conquer their tech dreams and stay ahead in an ever-evolving digital universe.</p>
                                </div>
                            </div>
                        </motion.div>
                    </div>

                    {/* Right Side: Sticky Geometric Animation */}
                    <div className="w-1/2 h-full bg-[#020202] flex items-center justify-center relative overflow-hidden shadow-2xl">
                        <motion.div
                            style={{ scale, rotate }}
                            className="grid grid-cols-5 gap-4 md:gap-8"
                        >
                            {[...Array(25)].map((_, i) => (
                                <motion.div
                                    key={i}
                                    style={{
                                        borderRadius: i % 2 === 0 ? borderRadius : "0%",
                                        rotate: i % 3 === 0 ? rotate : 0
                                    }}
                                    className={`w-6 h-6 md:w-10 md:h-10 ${i % 2 === 0 ? 'bg-[#00FFAA]' : 'bg-white'}`}
                                />
                            ))}
                        </motion.div>
                    </div>
                </div>
            </section>

            {/* 3. Our Values Section */}
            <section className="py-32 container mx-auto px-6 md:px-12 bg-white">
                <h2 className="text-6xl md:text-8xl font-serif mb-24">Our<br />values</h2>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                    {VALUES.map((val, idx) => (
                        <motion.div
                            key={idx}
                            initial={{ opacity: 0, y: 30 }}
                            whileInView={{ opacity: 1, y: 0 }}
                            viewport={{ once: true, margin: "-100px" }}
                            transition={{ delay: idx * 0.1 }}
                            className="flex flex-col group"
                        >
                            <div className="relative aspect-[4/3] mb-8 w-full">
                                <div className="absolute inset-0 overflow-hidden bg-gray-100">
                                    <Image
                                        src={val.img}
                                        alt={val.title}
                                        fill
                                        className="object-cover grayscale group-hover:grayscale-0 transition-all duration-500"
                                    />
                                </div>
                                {/* Cyan Geometric Overlays */}
                                {val.squares.map((sq, sIdx) => (
                                    <div
                                        key={sIdx}
                                        className="absolute bg-[#00FFAA] mix-blend-multiply z-10 transition-transform duration-500 group-hover:scale-110"
                                        style={{
                                            top: sq.top,
                                            bottom: sq.bottom,
                                            left: sq.left,
                                            right: sq.right,
                                            width: `${sq.size}px`,
                                            height: `${sq.size}px`,
                                            clipPath: sq.type === 'diamond' ? 'polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%)' : sq.type === 'triangle' ? 'polygon(100% 100%, 0 100%, 100% 0)' : 'none'
                                        }}
                                    />
                                ))}
                            </div>

                            <h3 className="text-2xl font-bold mb-4 font-sans">{val.title}</h3>
                            <p className="text-gray-600 leading-relaxed font-sans">{val.desc}</p>
                        </motion.div>
                    ))}
                </div>
            </section>
        </main>
    );
}

"use client";

import { motion } from "framer-motion";
import { CheckCircle2 } from "lucide-react";

export function About() {
    const values = [
        "Innovation at the core",
        "Uncompromising quality",
        "Transparent processes",
        "User-centric design",
    ];

    return (
        <section id="about" className="py-24 relative">
            <div className="container mx-auto px-6 md:px-12">
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">
                    <motion.div
                        initial={{ opacity: 0, x: -30 }}
                        whileInView={{ opacity: 1, x: 0 }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.8 }}
                        className="space-y-8"
                    >
                        <div>
                            <h2 className="text-4xl md:text-6xl font-serif tracking-tight mb-4 text-white">
                                Pioneering the next era of <span className="text-blue-500">digital products.</span>
                            </h2>
                            <p className="text-gray-400 text-lg leading-relaxed">
                                At Syntax, we don't just write code; we architect solutions that elevate businesses. Our team of expert engineers and designers collaborate to deliver software that is both elegant and robust.
                            </p>
                        </div>

                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                            {values.map((value, idx) => (
                                <div key={idx} className="flex items-center gap-3">
                                    <CheckCircle2 className="text-blue-500" size={20} />
                                    <span className="text-gray-300 font-medium">{value}</span>
                                </div>
                            ))}
                        </div>
                    </motion.div>

                    <motion.div
                        initial={{ opacity: 0, scale: 0.95 }}
                        whileInView={{ opacity: 1, scale: 1 }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.8 }}
                        className="relative"
                    >
                        <div className="aspect-[4/3] rounded-2xl overflow-hidden relative border border-white/5 p-2 bg-white/5">
                            <div className="w-full h-full bg-neutral-900 rounded-xl overflow-hidden relative">
                                {/* Placeholder for an actual team/office image */}
                                <div className="absolute inset-0 bg-gradient-to-tr from-blue-600/20 to-blue-900/20" />
                                <div className="absolute inset-0 flex items-center justify-center">
                                    <span className="text-white/20 font-medium">Abstract / Team Preview</span>
                                </div>
                            </div>
                        </div>

                        {/* Floating stats card */}
                        <div className="absolute -bottom-6 -left-6 bg-[#020202] border border-white/10 p-6 rounded-2xl inline-block shadow-2xl">
                            <div className="text-4xl font-serif text-white">
                                10+
                            </div>
                            <div className="text-sm text-gray-400 font-medium mt-1">Years Experience</div>
                        </div>
                    </motion.div>
                </div>
            </div>
        </section>
    );
}

"use client";

import { motion } from "framer-motion";
import { MapPin, Phone, Mail, Send } from "lucide-react";
import React, { useState } from "react";

export function Contact() {
    const [formState, setFormState] = useState({ name: "", email: "", message: "" });
    const [isSubmitting, setIsSubmitting] = useState(false);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        setIsSubmitting(true);
        // Simulate API call
        setTimeout(() => {
            setIsSubmitting(false);
            setFormState({ name: "", email: "", message: "" });
            alert("Message sent successfully!");
        }, 1500);
    };

    return (
        <section id="contact" className="py-32 bg-[#020202] relative z-10 border-t border-white/5">
            <div className="container mx-auto px-6 md:px-12">
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-16">
                    <motion.div
                        initial={{ opacity: 0, x: -30 }}
                        whileInView={{ opacity: 1, x: 0 }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.6 }}
                    >
                        <h2 className="text-4xl md:text-6xl font-serif text-white mb-6">
                            Let's build something extraordinary.
                        </h2>
                        <p className="text-gray-400 text-lg mb-16">
                            Have a project in mind? We'd love to hear about it. Drop us a message and our team will get back to you within 24 hours.
                        </p>

                        <div className="space-y-8">
                            <div className="flex items-start gap-6 group">
                                <div className="w-14 h-14 rounded-full border border-white/10 bg-white/[0.02] flex items-center justify-center shrink-0 group-hover:bg-blue-600/10 group-hover:border-blue-500/30 transition-colors">
                                    <Mail className="text-blue-500" size={24} />
                                </div>
                                <div>
                                    <h4 className="text-white font-medium mb-1">Email Us</h4>
                                    <a href="mailto:hello@syntax.dev" className="text-gray-400 hover:text-white transition-colors text-lg">hello@syntax.dev</a>
                                </div>
                            </div>
                            <div className="flex items-start gap-6 group">
                                <div className="w-14 h-14 rounded-full border border-white/10 bg-white/[0.02] flex items-center justify-center shrink-0 group-hover:bg-blue-600/10 group-hover:border-blue-500/30 transition-colors">
                                    <Phone className="text-blue-500" size={24} />
                                </div>
                                <div>
                                    <h4 className="text-white font-medium mb-1">Call Us</h4>
                                    <a href="tel:+1234567890" className="text-gray-400 hover:text-white transition-colors text-lg">+1 (555) 123-4567</a>
                                </div>
                            </div>
                            <div className="flex items-start gap-6 group">
                                <div className="w-14 h-14 rounded-full border border-white/10 bg-white/[0.02] flex items-center justify-center shrink-0 group-hover:bg-blue-600/10 group-hover:border-blue-500/30 transition-colors">
                                    <MapPin className="text-blue-500" size={24} />
                                </div>
                                <div>
                                    <h4 className="text-white font-medium mb-1">Visit Us</h4>
                                    <p className="text-gray-400 text-lg">123 Innovation Drive<br />Tech District, San Francisco</p>
                                </div>
                            </div>
                        </div>
                    </motion.div>

                    <motion.div
                        initial={{ opacity: 0, y: 30 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.6, delay: 0.2 }}
                        className="bg-white/[0.02] border border-white/5 p-10 md:p-12 rounded-3xl"
                    >
                        <form onSubmit={handleSubmit} className="space-y-6">
                            <div>
                                <label htmlFor="name" className="block text-sm font-medium text-gray-400 mb-2 uppercase tracking-wider">Full Name</label>
                                <input
                                    type="text"
                                    id="name"
                                    required
                                    value={formState.name}
                                    onChange={(e) => setFormState({ ...formState, name: e.target.value })}
                                    className="w-full bg-white/[0.03] border border-white/10 rounded-xl px-4 py-4 text-white focus:outline-none focus:border-blue-500/50 focus:bg-white/[0.05] transition-all"
                                    placeholder="John Doe"
                                />
                            </div>
                            <div>
                                <label htmlFor="email" className="block text-sm font-medium text-gray-400 mb-2 uppercase tracking-wider">Email Address</label>
                                <input
                                    type="email"
                                    id="email"
                                    required
                                    value={formState.email}
                                    onChange={(e) => setFormState({ ...formState, email: e.target.value })}
                                    className="w-full bg-white/[0.03] border border-white/10 rounded-xl px-4 py-4 text-white focus:outline-none focus:border-blue-500/50 focus:bg-white/[0.05] transition-all"
                                    placeholder="john@company.com"
                                />
                            </div>
                            <div>
                                <label htmlFor="message" className="block text-sm font-medium text-gray-400 mb-2 uppercase tracking-wider">Project Details</label>
                                <textarea
                                    id="message"
                                    required
                                    rows={5}
                                    value={formState.message}
                                    onChange={(e) => setFormState({ ...formState, message: e.target.value })}
                                    className="w-full bg-white/[0.03] border border-white/10 rounded-xl px-4 py-4 text-white focus:outline-none focus:border-blue-500/50 focus:bg-white/[0.05] transition-all resize-none"
                                    placeholder="Tell us about your project goals..."
                                />
                            </div>
                            <button
                                type="submit"
                                disabled={isSubmitting}
                                className="w-full py-4 rounded-full bg-blue-600 text-white font-semibold hover:bg-blue-500 transition-colors flex items-center justify-center gap-2 disabled:opacity-70 disabled:cursor-not-allowed mt-4 shadow-[0_0_20px_rgba(0,102,255,0.3)] hover:shadow-[0_0_30px_rgba(0,102,255,0.5)]"
                            >
                                {isSubmitting ? "Sending..." : (
                                    <>Send Message <Send size={18} /></>
                                )}
                            </button>
                        </form>
                    </motion.div>
                </div>
            </div>
        </section>
    );
}

"use client";

import { motion } from "framer-motion";
import Link from "next/link";
import { ArrowRight } from "lucide-react";

export function Cta() {
    return (
        <section className="py-24 relative overflow-hidden">
            <div className="absolute inset-0 z-0">
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full max-w-4xl h-[400px] bg-blue-600/20 rounded-full blur-[120px]" />
            </div>

            <div className="container mx-auto px-6 md:px-12 relative z-10">
                <motion.div
                    initial={{ opacity: 0, scale: 0.95 }}
                    whileInView={{ opacity: 1, scale: 1 }}
                    viewport={{ once: true }}
                    transition={{ duration: 0.6 }}
                    className="bg-[#020202] border border-white/5 rounded-3xl p-12 md:p-24 text-center relative overflow-hidden"
                >
                    <div className="absolute inset-0 bg-blue-600/5 mix-blend-screen pointer-events-none" />

                    <h2 className="text-4xl md:text-7xl font-serif mb-8 text-white leading-tight relative z-10">
                        Ready to scale your <br className="hidden md:block" />
                        digital presence?
                    </h2>
                    <p className="text-xl text-gray-400 mb-12 max-w-2xl mx-auto relative z-10">
                        Let's collaborate to build software solutions that engage users, streamline operations, and drive real business growth.
                    </p>
                    <div className="flex flex-col sm:flex-row items-center justify-center gap-6 relative z-10">
